import React from "react";

function GridOptions(){
     return (
            <div className="GridOptions">
                <label for="gridRows">grid-row: </label>
                <input name="gridRows" type="number"></input>
                <label for="gridColumns">grid-column: </label>
                <input name="gridColumns" type="number"></input>
            </div>
        );
}

export default GridOptions;
